module top_module(clk, rstn, load, shift, parallelin, lsbout);input clk; 
  input rstn; 
  input load; 
  input shift; 
  input [7:0] parallelin; 
  output lsbout; 
  reg [7:0] data_reg; 
  assign lsbout = data_reg[0]; 
  always @(posedge clk or negedge rstn) begin 
  if(rstn == 0) 
  data_reg <= 0; 
  else begin 
  if(load == 1) 
  data_reg <= parallelin; 
  else if (shift == 1) begin 
  data_reg[6:0] <= data_reg[7:1]; 
  data_reg[7] <= 0; 
  end 
  end 
  end 
 endmodule
